node -e "const fs=require('fs'); fs.writeFileSync('src/money.js', 'export function parseCurrency(value) {
  const normalized = String(value ?? 0).replace(/[$,]/g, '');
  const parsed = Number(normalized);
  if (!Number.isFinite(parsed)) throw new Error(`Invalid currency value: ${value}`);
  return parsed;
}

export function formatCurrency(amount) {
  return `$${amount.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}
'); fs.writeFileSync('src/invoice.js', 'import { formatCurrency, parseCurrency } from './money.js';

export function invoiceTotal(invoice) {
  const subtotal = invoice.items.reduce((sum, item) => sum + parseCurrency(item.amount), 0);
  return subtotal - parseCurrency(invoice.discount ?? '$0');
}

export function invoiceSummary(invoice) {
  return {
    id: invoice.id,
    itemCount: invoice.items.length,
    total: formatCurrency(invoiceTotal(invoice)),
  };
}
');"
